def compute_score() -> tuple[str, float]:
    # Use VLM to check whether three specified bullet sentences are present on slide 9
    slide_9_image = None
    if len(ppt_diff.modified_slides) == 0:
        return "No modifications detected.", 0.0
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 9:
                slide_9_image = s.image_path
                break
        except Exception:
            continue
    if not slide_9_image:
        return "Slide 9 screenshot not found.", 0.0

    prompt = (
        "Look at slide 9 and read the bullet points. We expect these three bullet sentences:\n"
        "1) 'The association may be stronger for obese adolescents than younger children'\n"
        "2) 'Obese children are also more likely to have increased risk of heart disease'\n"
        "3) 'Obese children are also more likely to develop asthma'\n"
        "Do all three of these sentences appear as separate bullet points? Respond YES if all three appear, PARTIAL if only one or two appear, or NONE if none appear. Include a brief justification."
    )

    try:
        response = vlm_call(images=[slide_9_image], prompt=prompt, temperature=0.1)
        resp = str(response).strip().upper()
        if resp.startswith('YES'):
            return response, 1.0
        elif 'PARTIAL' in resp:
            return response, 0.5
        elif resp.startswith('NONE') or resp.startswith('NO'):
            return response, 0.0
        else:
            return f"Unclear VLM response: {response}", 0.0
    except Exception as e:
        return f"Error during VLM check: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    # Use VLM to check whether the first bullet on slide 9 is numbered as '1.'
    slide_9_image = None
    if len(ppt_diff.modified_slides) == 0:
        return "No modifications detected.", 0.0
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 9:
                slide_9_image = s.image_path
                break
        except Exception:
            continue
    if not slide_9_image:
        return "Slide 9 screenshot not found.", 0.0

    prompt = (
        "Look at slide 9. Focus on the main content bullet list (ignore the title).\n"
        "Is the FIRST bullet explicitly numbered as '1.' (arabic number followed by a period)?\n"
        "Respond YES or NO and include a brief justification."
    )
    try:
        response = vlm_call(images=[slide_9_image], prompt=prompt, temperature=0.1)
        resp = str(response).strip().lower()
        if resp.startswith('yes'):
            return response, 1.0
        elif resp.startswith('no'):
            return response, 0.0
        else:
            return f"Unclear VLM response: {response}", 0.0
    except Exception as e:
        return f"Error during VLM check: {str(e)}", 0.0
